     3→import { useState } from "react";
     4→
     5→const LAW_LINKS: Record<string, { url: string; summary: string }> = {
     6→  "EU AI Act": {
     7→    url: "https://artificialintelligenceact.eu/",
     8→    summary: "The European Union's comprehensive regulation on artificial intelligence, classifying AI systems by risk level and imposing obligations on developers and deployers. High-risk systems face strict requirements around transparency, human oversight, and data governance.",
     9→  },
    10→  "GDPR": {
    11→    url: "https://gdpr.eu/",
    12→    summary: "The General Data Protection Regulation governs how organizations collect, store, and use personal data of EU residents. It includes AI-specific implications around automated decision-making (Article 22) and data protection impact assessments (Article 35).",
    13→  },
    14→  "NIST AI RMF": {
    15→    url: "https://www.nist.gov/system/files/documents/2023/01/26/AI%20RMF%201.0.pdf",
    16→    summary: "The U.S. National Institute of Standards and Technology's AI Risk Management Framework. A voluntary framework helping organizations identify, assess, and manage AI risks across four functions: Govern, Map, Measure, and Manage.",
    17→  },
    18→  "ISO/IEC 42001": {
    19→    url: "https://www.iso.org/standard/81230.html",
    20→    summary: "An international standard for AI management systems, providing organizations with a structured framework to responsibly develop and use AI. Certifiable, it demonstrates to partners and regulators that your AI practices meet global standards.",
    21→  },
    22→  "CCPA": {
    23→    url: "https://oag.ca.gov/privacy/ccpa",
    24→    summary: "The California Consumer Privacy Act gives California residents rights over their personal data, including data used in AI systems. It requires transparency about data collection and grants opt-out rights for data sales.",
    25→  },
    26→  "HIPAA": {
    27→    url: "https://www.hhs.gov/hipaa/index.html",
    28→    summary: "The Health Insurance Portability and Accountability Act governs the use of protected health information. AI systems in healthcare must comply with HIPAA's privacy and security rules when processing patient data.",
    29→  },
    30→  "FFIEC": {
    31→    url: "https://www.ffiec.gov/",
    32→    summary: "The Federal Financial Institutions Examination Council issues guidance for AI use in banking and financial services, covering model risk management, fair lending, and explainability requirements for algorithmic decisions.",
    33→  },
    34→  "FDA AI/ML Guidance": {
    35→    url: "https://www.fda.gov/medical-devices/software-medical-device-samd/artificial-intelligence-and-machine-learning-aiml-enabled-medical-devices",
    36→    summary: "FDA guidance for AI and machine learning used in medical devices and clinical decision support. Requires pre-market approval processes, ongoing monitoring, and transparency about how AI-driven medical tools make recommendations.",
    37→  },
    38→  "UK ICO AI Guidance": {
    39→    url: "https://ico.org.uk/for-organisations/guide-to-data-protection/key-data-protection-themes/explaining-decisions-made-with-artificial-intelligence/",
    40→    summary: "The UK Information Commissioner's Office guidance on using AI in compliance with UK GDPR. Covers fairness, accountability, and the requirement to explain automated decisions to individuals.",
    41→  },
    42→  "Canada AIDA": {
    43→    url: "https://ised-isde.canada.ca/site/innovation-better-canada/en/artificial-intelligence-data-act",
    44→    summary: "Canada's Artificial Intelligence and Data Act proposes a risk-based regulatory framework for high-impact AI systems, requiring impact assessments, human oversight, and transparency obligations for organizations deploying AI in Canada.",
    45→  },
    46→  "OECD AI Principles": {
    47→    url: "https://oecd.ai/en/ai-principles",
    48→    summary: "Internationally adopted principles recommending that AI systems be transparent, explainable, fair, and accountable. Endorsed by over 40 countries, these principles form the ethical backbone of many national AI regulations.",
    49→  },
    50→  "IEEE Ethically Aligned Design": {
    51→    url: "https://standards.ieee.org/industry-connections/ec/autonomous-systems/",
    52→    summary: "IEEE's framework for embedding ethical considerations into AI and autonomous systems design. Covers human rights, well-being, data agency, and accountability, and is used as a reference standard by engineers and governance teams.",
    53→  },
    54→  "China AI Regulations": {
    55→    url: "https://www.cac.gov.cn/",
    56→    summary: "China has enacted several AI-specific regulations including rules on algorithmic recommendation, deep synthesis (deepfakes), and generative AI. Organizations operating in China must register AI systems with regulators and meet content security requirements.",
    57→  },
    58→};
    59→
    60→const QUESTIONS = [
    61→  {
    62→    id: "geography",
    63→    question: "Where does your organization primarily operate?",
    64→    type: "multi",
    65→    options: ["United States", "European Union", "United Kingdom", "Canada", "China", "Global / Multiple Regions", "Other"],
    66→  },
    67→  {
    68→    id: "size",
    69→    question: "What is your organization's size?",
    70→    type: "single",
    71→    options: ["Startup (1 to 50 employees)", "Small or mid-size (51 to 500 employees)", "Mid-market (501 to 5,000 employees)", "Enterprise (5,000 or more employees)"],
    72→  },
    73→  {
    74→    id: "sector",
    75→    question: "What sector does your organization operate in?",
    76→    type: "single",
    77→    options: ["Healthcare or Life Sciences", "Financial Services or Fintech", "Government or Public Sector", "Education", "Technology or SaaS", "Nonprofit or Social Impact", "Retail or E-commerce", "Media or Entertainment", "Manufacturing or Industrial", "Legal or Professional Services", "Other"],
    78→  },
    79→  {
    80→    id: "org_type",
    81→    question: "Which best describes your organization's structure?",
    82→    type: "single",
    83→    options: ["For-profit corporation", "Nonprofit 501(c)(3)", "Nonprofit 501(c)(4) or other advocacy organization", "Government agency or public institution", "Academic or research institution", "Social enterprise or B Corp", "Other"],
    84→  },
    85→  {
    86→    id: "ai_use",
    87→    question: "How is AI currently used in your organization?",
    88→    type: "multi",
    89→    options: ["Customer-facing products or services", "Internal operations or automation", "Decision-making systems (hiring, lending, admissions, etc.)", "Research and development", "Data analytics and reporting", "Donor or constituent engagement", "Content generation or communications", "We are exploring AI but have not deployed yet"],
    90→  },
    91→  {
    92→    id: "risk",
    93→    question: "How would you characterize your AI use cases in terms of impact on people?",
    94→    type: "single",
    95→    options: ["Low impact: informational or creative tools only", "Moderate impact: operational tools that affect internal processes", "High impact: systems that affect individuals' rights, access to services, or safety", "We are not sure"],
    96→  },
    97→  {
    98→    id: "data",
    99→    question: "What types of data does your AI system use or process?",
   100→    type: "multi",
   101→    options: ["Personal data of EU or UK residents", "Personal data of US residents", "Health or biometric data", "Financial or credit data", "Data about minors", "Donor or beneficiary data", "Minimal or no personal data", "Not sure"],
   102→  },
   103→  {
   104→    id: "maturity",
   105→    question: "How would you describe your current AI governance posture?",
   106→    type: "single",
   107→    options: ["No governance practices in place", "Informal practices with no documentation", "Some written policies, inconsistently applied", "Formal program with dedicated ownership", "Advanced: audited, certified, or formally regulated"],
   108→  },
   109→  {
   110→    id: "concern",
   111→    question: "What is your organization most concerned about right now?",
   112→    type: "multi",
   113→    options: ["Legal liability or regulatory fines", "Reputational damage from AI misuse", "Harm to the communities or individuals we serve", "Lack of internal accountability", "Preparing for an audit or certification", "Not knowing where to start"],
   114→  },
   115→  {
   116→    id: "goal",
   117→    question: "What is your primary governance goal?",
   118→    type: "single",
   119→    options: ["Achieve regulatory compliance", "Build internal accountability and culture", "Prepare for third-party audits or certification", "Establish ethical AI principles and practices", "Reduce legal and reputational risk", "Protect the people our organization serves", "Not sure: I need guidance on where to begin"],
   120→  },
