   122→
   123→interface Framework {
   124→  name: string;
   125→  relevance: string;
   126→  reason: string;
   127→}
   128→
   129→interface PriorityItem {
   130→  title: string;
   131→  description: string;
   132→}
   133→
   134→interface Result {
   135→  riskTier: string;
   136→  summary: string;
   137→  primaryFrameworks: Framework[];
   138→  topPriorities: PriorityItem[];
   139→  immediateActions: PriorityItem[];
   140→  jurisdictionalNote: string;
   141→}
   142→
   143→const riskConfig: Record<string, { color: string; bg: string; border: string }> = {
   144→  Low: { color: "#2e7d32", bg: "rgba(46,125,50,0.1)", border: "rgba(46,125,50,0.4)" },
   145→  Moderate: { color: "#b45309", bg: "rgba(180,83,9,0.1)", border: "rgba(180,83,9,0.4)" },
   146→  High: { color: "#c2410c", bg: "rgba(194,65,12,0.1)", border: "rgba(194,65,12,0.4)" },
   147→  Critical: { color: "#991b1b", bg: "rgba(153,27,27,0.12)", border: "rgba(153,27,27,0.4)" },
   148→};
   149→
   150→export default function CompassApp() {
   151→  const [step, setStep] = useState<"intro" | "questions" | "loading" | "results">("intro");
   152→  const [currentQ, setCurrentQ] = useState(0);
   153→  const [answers, setAnswers] = useState<Record<string, string | string[]>>({});
   154→  const [result, setResult] = useState<Result | null>(null);
   155→  const [error, setError] = useState<string | null>(null);
   156→  const [tooltip, setTooltip] = useState<string | null>(null);
   157→
   158→  const currentQuestion = QUESTIONS[currentQ];
   159→
   160→  function handleSelect(qId: string, value: string, isMulti: boolean) {
   161→    if (isMulti) {
   162→      const current = (answers[qId] as string[]) || [];
   163→      const updated = current.includes(value)
   164→        ? current.filter((v) => v !== value)
   165→        : [...current, value];
   166→      setAnswers({ ...answers, [qId]: updated });
   167→    } else {
   168→      setAnswers({ ...answers, [qId]: value });
   169→    }
   170→  }
   171→
   172→  function canProceed() {
   173→    const val = answers[currentQuestion?.id];
   174→    if (!val) return false;
   175→    if (Array.isArray(val)) return val.length > 0;
   176→    return true;
   177→  }
   178→
   179→  function nextQuestion() {
   180→    if (currentQ < QUESTIONS.length - 1) {
   181→      setCurrentQ(currentQ + 1);
   182→    } else {
   183→      submitAssessment();
   184→    }
   185→  }
   186→
   187→  async function submitAssessment() {
   188→    setStep("loading");
   189→    try {
   190→      const formatted = QUESTIONS.map((q) => {
   191→        const ans = answers[q.id];
   192→        const ansText = Array.isArray(ans) ? ans.join(", ") : (ans || "No answer");
   193→        return `${q.question}\nAnswer: ${ansText}`;
   194→      }).join("\n\n");
   195→
   196→      const response = await fetch("/api/analyze", {
   197→        method: "POST",
   198→        headers: { "Content-Type": "application/json" },
   199→        body: JSON.stringify({ answers: formatted }),
   200→      });
   201→
   202→      const data = await response.json();
   203→      if (!response.ok) throw new Error(data.error || "Request failed");
   204→      setResult(data);
   205→      setStep("results");
   206→    } catch (e) {
   207→      setError("Something went wrong generating your profile. Please try again.");
   208→      setStep("questions");
   209→    }
   210→  }
   211→
   212→  function restart() {
   213→    setStep("intro");
   214→    setCurrentQ(0);
   215→    setAnswers({});
   216→    setResult(null);
   217→    setError(null);
   218→    setTooltip(null);
   219→  }
   220→
   221→  function renderFrameworkName(name: string) {
   222→    const law = LAW_LINKS[name];
   223→    if (!law) return <span style={{ fontWeight: 700, color: "var(--text-main)" }}>{name}</span>;
   224→    return (
   225→      <span style={{ position: "relative", display: "inline-flex", alignItems: "center", gap: "0.4rem" }}>
   226→        <a
   227→          href={law.url}
   228→          target="_blank"
   229→          rel="noopener noreferrer"
   230→          onClick={(e) => e.stopPropagation()}
   231→          style={{ color: "var(--gold)", textDecoration: "underline", textDecorationStyle: "dotted", fontWeight: 700 }}
   232→        >
   233→          {name}
   234→        </a>
   235→        <button
   236→          onClick={(e) => { e.stopPropagation(); setTooltip(tooltip === name ? null : name); }}
   237→          style={{
   238→            background: "rgba(196,165,90,0.15)", border: "1px solid rgba(196,165,90,0.35)",
   239→            borderRadius: "50%", width: "17px", height: "17px", fontSize: "10px",
   240→            color: "var(--gold)", cursor: "pointer", display: "inline-flex",
   241→            alignItems: "center", justifyContent: "center", fontWeight: 700, flexShrink: 0,
   242→          }}
   243→        >?</button>
   244→        {tooltip === name && (
   245→          <div style={{
   246→            position: "absolute", top: "calc(100% + 8px)", left: 0, zIndex: 200,
   247→            background: "#16203a", border: "1px solid rgba(196,165,90,0.3)",
   248→            borderRadius: "10px", padding: "1rem 1.15rem", width: "300px",
   249→            fontSize: "0.8rem", color: "#b0aac8", lineHeight: 1.7,
   250→            boxShadow: "0 12px 40px rgba(0,0,0,0.5)",
   251→          }}>
   252→            <div style={{ fontWeight: 700, color: "var(--gold)", marginBottom: "0.4rem" }}>{name}</div>
   253→            {law.summary}
   254→            <div style={{ marginTop: "0.65rem" }}>
   255→              <a href={law.url} target="_blank" rel="noopener noreferrer"
   256→                onClick={(e) => e.stopPropagation()}
   257→                style={{ color: "var(--gold)", fontSize: "0.78rem", textDecoration: "none" }}>
   258→                View official documentation
   259→              </a>
   260→            </div>
   261→          </div>
   262→        )}
   263→      </span>
   264→    );
   265→  }
   266→
   267→  return (
   268→    <>
   269→      <style>{`
   270→        @import url('https://fonts.googleapis.com/css2?family=Playfair+Display:ital,wght@0,400;0,600;0,700;1,400;1,600&family=Inter:wght@300;400;500;600&display=swap');
   271→        * { box-sizing: border-box; margin: 0; padding: 0; }
   272→        :root {
   273→          --navy-deep: #0d1426; --navy-mid: #1e2d5a;
   274→          --gold: #c4a55a; --gold-light: #dfc080; --gold-pale: rgba(196,165,90,0.1);
   275→          --text-main: #eeeaf5; --text-muted: #9490b2; --text-dim: #5e5a7a;
   276→          --border: rgba(196,165,90,0.16);
   277→        }
   278→        body { font-family: 'Inter', sans-serif; background: var(--navy-deep); color: var(--text-main); min-height: 100vh; }
   279→        .app {
   280→          min-height: 100vh;
   281→          background: radial-gradient(ellipse at 10% 5%, rgba(196,165,90,0.05) 0%, transparent 40%),
   282→                      radial-gradient(ellipse at 90% 95%, rgba(30,45,90,0.7) 0%, transparent 50%),
   283→                      var(--navy-deep);
   284→          display: flex; flex-direction: column; align-items: center; justify-content: center; padding: 2rem 1rem;
   285→        }
   286→        .card {
   287→          background: rgba(20,30,65,0.65); border: 1px solid var(--border);
   288→          border-radius: 16px; backdrop-filter: blur(18px);
   289→          width: 100%; max-width: 700px; padding: 3rem 3.5rem;
   290→          animation: fadeUp 0.4s ease both;
   291→        }
   292→        @keyframes fadeUp { from { opacity:0; transform:translateY(16px); } to { opacity:1; transform:translateY(0); } }
   293→        .logo-wrap { display:flex; justify-content:center; margin-bottom:2.5rem; }
   294→        .logo-wrap img { height:88px; width:auto; object-fit:contain; }
   295→        .headline { font-family:'Playfair Display',serif; font-size:2.5rem; font-weight:400; line-height:1.2; margin-bottom:1.5rem; color:var(--text-main); }
   296→        .headline em { font-style:italic; color:var(--gold-light); }
   297→        .intro-body { font-size:0.93rem; color:var(--text-muted); line-height:1.85; margin-bottom:1.25rem; font-weight:300; }
   298→        .intro-body strong { color:var(--text-main); font-weight:500; }
   299→        .divider-gold { width:48px; height:2px; background:linear-gradient(90deg,var(--gold),transparent); margin:1.5rem 0; }
   300→        .btn-primary { background:linear-gradient(135deg,var(--gold),#a8893f); color:#0d1426; border:none; border-radius:8px; padding:0.9rem 2.25rem; font-family:'Inter',sans-serif; font-size:0.82rem; font-weight:700; cursor:pointer; letter-spacing:0.08em; text-transform:uppercase; transition:all 0.2s; }
   301→        .btn-primary:hover { opacity:0.87; transform:translateY(-1px); }
   302→        .btn-primary:disabled { opacity:0.3; cursor:not-allowed; transform:none; }
   303→        .btn-ghost { background:transparent; color:var(--text-muted); border:1px solid rgba(196,165,90,0.22); border-radius:8px; padding:0.9rem 1.75rem; font-family:'Inter',sans-serif; font-size:0.82rem; font-weight:500; cursor:pointer; letter-spacing:0.05em; transition:all 0.2s; }
   304→        .btn-ghost:hover { border-color:var(--gold); color:var(--gold); }
   305→        .progress-wrap { margin-bottom:2.25rem; }
   306→        .progress-meta { display:flex; justify-content:space-between; margin-bottom:0.55rem; }
   307→        .progress-label { font-size:0.7rem; text-transform:uppercase; letter-spacing:0.1em; color:var(--text-dim); font-weight:500; }
   308→        .progress-bar { height:2px; background:rgba(196,165,90,0.1); border-radius:2px; overflow:hidden; }
   309→        .progress-fill { height:100%; background:linear-gradient(90deg,var(--gold),var(--gold-light)); border-radius:2px; transition:width 0.4s ease; }
   310→        .q-label { font-size:0.68rem; text-transform:uppercase; letter-spacing:0.14em; color:var(--gold); margin-bottom:0.55rem; font-weight:600; }
   311→        .q-text { font-family:'Playfair Display',serif; font-size:1.5rem; font-weight:400; line-height:1.35; margin-bottom:0.4rem; color:var(--text-main); }
   312→        .multi-hint { font-size:0.77rem; color:var(--text-dim); margin-bottom:1.2rem; font-style:italic; }
   313→        .options { display:flex; flex-direction:column; gap:0.45rem; margin-bottom:2rem; }
   314→        .option { padding:0.78rem 1.1rem; border-radius:8px; border:1px solid rgba(196,165,90,0.13); background:rgba(196,165,90,0.02); color:var(--text-muted); cursor:pointer; transition:all 0.15s; font-size:0.88rem; text-align:left; font-family:'Inter',sans-serif; line-height:1.4; }
   315→        .option:hover { border-color:rgba(196,165,90,0.38); color:var(--text-main); background:rgba(196,165,90,0.05); }
   316→        .option.selected { border-color:var(--gold); background:var(--gold-pale); color:var(--text-main); }
   317→        .nav-row { display:flex; justify-content:space-between; align-items:center; }
   318→        .error-msg { background:rgba(153,27,27,0.1); border:1px solid rgba(239,68,68,0.22); border-radius:8px; padding:0.8rem 1rem; color:#fca5a5; font-size:0.83rem; margin-bottom:1.25rem; }
   319→        .loading-center { text-align:center; padding:2rem 0 1rem; }
   320→        .spinner { width:42px; height:42px; border:2px solid rgba(196,165,90,0.13); border-top-color:var(--gold); border-radius:50%; animation:spin 0.85s linear infinite; margin:0 auto 1.75rem; }
   321→        @keyframes spin { to { transform:rotate(360deg); } }
   322→        .loading-headline { font-family:'Playfair Display',serif; font-size:1.45rem; font-weight:400; color:var(--text-main); margin-bottom:0.5rem; }
   323→        .loading-sub { font-size:0.83rem; color:var(--text-muted); font-weight:300; }
   324→        .risk-badge { display:inline-flex; align-items:center; gap:0.45rem; padding:0.28rem 0.85rem; border-radius:100px; font-size:0.7rem; font-weight:700; letter-spacing:0.1em; text-transform:uppercase; margin-bottom:0.85rem; border:1px solid; }
   325→        .results-headline { font-family:'Playfair Display',serif; font-size:1.9rem; font-weight:400; color:var(--text-main); line-height:1.2; }
   326→        .results-headline em { font-style:italic; color:var(--gold-light); }
   327→        .section-label { font-size:0.66rem; text-transform:uppercase; letter-spacing:0.14em; color:var(--gold); font-weight:700; margin-bottom:0.8rem; }
   328→        .summary-text { font-size:0.91rem; color:var(--text-muted); line-height:1.85; font-weight:300; }
   329→        .divider { height:1px; background:rgba(196,165,90,0.1); margin:1.65rem 0; }
   330→        .frameworks { display:flex; flex-direction:column; gap:0.6rem; }
   331→        .fw-item { display:flex; align-items:flex-start; gap:0.9rem; padding:0.85rem 1rem; border-radius:10px; background:rgba(196,165,90,0.03); border:1px solid rgba(196,165,90,0.1); }
   332→        .fw-badge { font-size:0.62rem; font-weight:700; letter-spacing:0.07em; text-transform:uppercase; padding:0.18rem 0.48rem; border-radius:4px; white-space:nowrap; margin-top:3px; flex-shrink:0; }
   333→        .fw-high { background:rgba(196,165,90,0.18); color:var(--gold); }
   334→        .fw-medium { background:rgba(148,163,184,0.12); color:#94a3b8; }
   335→        .fw-low { background:rgba(100,116,139,0.1); color:#64748b; }
   336→        .fw-reason { font-size:0.8rem; color:var(--text-muted); line-height:1.55; font-weight:300; margin-top:0.25rem; }
