            <div
              className="risk-badge"
              style={{
                color: riskConfig[result.riskTier]?.color || "#c4a55a",
                background: riskConfig[result.riskTier]?.bg || "rgba(196,165,90,0.1)",
                borderColor: riskConfig[result.riskTier]?.border || "rgba(196,165,90,0.4)",
              }}
