export default function CompassApp() {
  const [step, setStep] = useState<"intro" | "questions" | "loading" | "results">("intro");
  const [currentQ, setCurrentQ] = useState(0);
  const [answers, setAnswers] = useState<Record<string, string | string[]>>({});
  const [result, setResult] = useState<Result | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [tooltip, setTooltip] = useState<string | null>(null);
  const [openSections, setOpenSections] = useState<Set<string>>(new Set(["overview"]));
  const [loadingMsg, setLoadingMsg] = useState(0);

  const currentQuestion = QUESTIONS[currentQ];

  useEffect(() => {
    if (step !== "loading") return;
    setLoadingMsg(0);
    const interval = setInterval(() => {
      setLoadingMsg((prev) => (prev + 1) % LOADING_MESSAGES.length);
    }, 1500);
    return () => clearInterval(interval);
  }, [step]);

  function toggleSection(id: string) {
    setOpenSections((prev) => {
      const next = new Set(prev);
      if (next.has(id)) next.delete(id);
      else next.add(id);
      return next;
    });
  }

  function renderAccordion(id: string, label: string, children: ReactNode) {
    const isOpen = openSections.has(id);
    return (
      <div className="accordion-row" key={id}>
        <button className="accordion-header" onClick={() => toggleSection(id)}>
          <span className="accordion-label">{label}</span>
          <svg
            className={`accordion-chevron${isOpen ? " open" : ""}`}
            width="16"
            height="16"
            viewBox="0 0 16 16"
            fill="none"
          >
            <path
              d="M4 6l4 4 4-4"
              stroke="currentColor"
              strokeWidth="1.5"
              strokeLinecap="round"
              strokeLinejoin="round"
            />
          </svg>
        </button>
        <div className={`accordion-body${isOpen ? " open" : ""}`}>
          <div className="accordion-body-inner">{children}</div>
        </div>
      </div>
    );
  }

  function handleSelect(qId: string, value: string, isMulti: boolean) {
    if (isMulti) {
      const current = (answers[qId] as string[]) || [];
      const updated = current.includes(value)
        ? current.filter((v) => v !== value)
        : [...current, value];
      setAnswers({ ...answers, [qId]: updated });
    } else {
      setAnswers({ ...answers, [qId]: value });
    }
  }

  function canProceed() {
    const val = answers[currentQuestion?.id];
    if (!val) return false;
    if (Array.isArray(val)) return val.length > 0;
    return true;
  }

  function nextQuestion() {
    if (currentQ < QUESTIONS.length - 1) {
      setCurrentQ(currentQ + 1);
    } else {
      submitAssessment();
    }
  }

  async function submitAssessment() {
    setStep("loading");
    try {
      const formatted = QUESTIONS.map((q) => {
        const ans = answers[q.id];
        const ansText = Array.isArray(ans) ? ans.join(", ") : (ans || "No answer");
        return `${q.question}\nAnswer: ${ansText}`;
      }).join("\n\n");

      const response = await fetch("/api/analyze", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ answers: formatted }),
      });

      const data = await response.json();
      if (!response.ok) throw new Error(data.error || "Request failed");
      setResult(data);
      setStep("results");
    } catch (e) {
      setError("Something went wrong generating your profile. Please try again.");
      setStep("questions");
    }
  }

  function restart() {
    setStep("intro");
    setCurrentQ(0);
    setAnswers({});
    setResult(null);
    setError(null);
    setTooltip(null);
    setOpenSections(new Set(["overview"]));
  }

